item.description:
agent any
            steps {
                checkout scm
                script {
                    // Git committer name
                    env.gitcommitname = sh (script: "git --no-pager show -s --format='%an' $GIT_COMMIT",returnStdout: true).trim()
                    echo "Git committer name: ${GITCOMMITNAME}"
                    // Git committer email
                    env.gitcommitemail = sh (script: "git --no-pager show -s --format='%ae' $GIT_COMMIT",returnStdout: true).trim()
                    echo "Git committer email: ${GITCOMMITEMAIL}"
                }
            }
`

};
        } else {
            return false;
        }
    }
